import React, { useState, useEffect } from 'react';

const defaultCategories = [
  { id: 'btech', label: 'B.Tech', badge: 'DEGREE', color: 'border-blue-500', bgColor: 'bg-blue-500', lightBg: 'bg-blue-50', programs: ['Information & Communication Technology (ICT)', 'Civil Engineering', 'Automobile Engineering', 'Mechanical Engineering', 'Metallurgical Engineering', 'Electrical Engineering', 'Electronics & Communication Engineering', 'Computer Engineering', 'Cyber Security', 'Information Technology', 'Computer Science Engineering', 'Aircraft Maintenance Engineering', 'Aeronautical Engineering', 'Aerospace Engineering', 'Defence Aerospace Engineering'] },
  { id: 'btech-dtd', label: 'B.Tech (D to D)', badge: 'LATERAL', color: 'border-amber-700', bgColor: 'bg-amber-700', lightBg: 'bg-amber-50', programs: ['Information & Communication Technology (ICT)', 'Civil Engineering', 'Automobile Engineering', 'Mechanical Engineering', 'Metallurgical Engineering', 'Electrical Engineering', 'Electronics & Communication Engineering', 'Computer Engineering', 'Cyber Security', 'Information Technology', 'Computer Science Engineering'] },
  { id: 'diploma', label: 'Diploma', badge: 'TECHNICAL', color: 'border-orange-500', bgColor: 'bg-orange-500', lightBg: 'bg-orange-50', programs: ['Information & Communication Technology (ICT)', 'Civil Engineering', 'Automobile Engineering', 'Mechanical Engineering', 'Computer Engineering', 'Electrical Engineering', 'Electronics & Communication Engineering'] },
  { id: 'mtech', label: 'M.Tech', badge: 'MASTERS', color: 'border-red-600', bgColor: 'bg-red-600', lightBg: 'bg-red-50', programs: ['CAD / CAM (Mechanical Engr.)', 'Construction Project Management (Civil Engg.)', 'Digital Communication (EC Engg.)', 'Electrical Power System', 'Industrial Metallurgy', 'Structural Engineering (Civil Engg.)', 'Data Science (Computer)', 'Cyber Security'] },
  { id: 'bdes', label: 'B.Des', badge: 'DESIGN', color: 'border-yellow-500', bgColor: 'bg-yellow-500', lightBg: 'bg-yellow-50', programs: ['Product Design', 'Interior Design', 'Fashion Design', 'Communication Design - (Graphic Design)'] },
  { id: 'mdes', label: 'M.Des', badge: 'MASTERS', color: 'border-teal-600', bgColor: 'bg-teal-600', lightBg: 'bg-teal-50', programs: ['Fashion Design', 'Interior Design', 'UI-UX Design'] },
  { id: 'bsc', label: 'B.Sc', badge: 'SCIENCE', color: 'border-blue-400', bgColor: 'bg-blue-400', lightBg: 'bg-blue-50', programs: ['Data Science', 'Computer Application (CA) & (IT)', 'Clinical Research (Hons)', 'Mathematics (Hons)', 'Physics (Hons)', 'Chemistry (Hons)', 'Cyber Security (Hons)', 'Microbiology (Hons)', 'Computer Science (AI & ML)'] },
  { id: 'msc', label: 'M.Sc', badge: 'MASTERS', color: 'border-indigo-600', bgColor: 'bg-indigo-600', lightBg: 'bg-indigo-50', programs: ['Information Technology (IT)', 'Clinical Research', 'Mathematics', 'Physics', 'Chemistry', 'Cyber Security', 'Microbiology'] },
  { id: 'mba-avia', label: 'MBA/BBA', badge: 'BUSINESS', color: 'border-purple-600', bgColor: 'bg-purple-600', lightBg: 'bg-purple-50', programs: ['Aviation Management', 'BBA', 'Marketing', 'Finance', 'Human Resource'] },
  { id: 'bca', label: 'BCA', badge: 'COMPUTER', color: 'border-cyan-500', bgColor: 'bg-cyan-500', lightBg: 'bg-cyan-50', programs: ['BCA'] },
  { id: 'mca', label: 'MCA', badge: 'POST-GRAD', color: 'border-rose-500', bgColor: 'bg-rose-500', lightBg: 'bg-rose-50', programs: ['MCA'] }
];

export default function AdminCategories({ confirmDelete, CenterModal }) {
  const [categories, setCategories] = useState([]);
  const [catForm, setCatForm] = useState({ id: '', label: '', badge: '', color: 'border-blue-500', bgColor: 'bg-blue-500', lightBg: 'bg-blue-50', programs: '' });

  // Navigation State
  const [selectedCategoryNav, setSelectedCategoryNav] = useState(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Program Details Editing
  const [programData, setProgramData] = useState({});
  const [selectedProgramEdit, setSelectedProgramEdit] = useState('');
  const [jsonInput, setJsonInput] = useState('');
  const [jsonError, setJsonError] = useState('');
  const [newCourseName, setNewCourseName] = useState('');

  useEffect(() => {
    const loadCategories = () => {
      const storedCat = localStorage.getItem('indus_categories');
      setCategories(storedCat ? JSON.parse(storedCat) : defaultCategories);
    };

    loadCategories();
    const storedProg = localStorage.getItem('indus_programData');
    setProgramData(storedProg ? JSON.parse(storedProg) : {});

    window.addEventListener('storage', loadCategories);
    return () => window.removeEventListener('storage', loadCategories);
  }, []);

  const saveCats = (data) => {
    setCategories(data);
    localStorage.setItem('indus_categories', JSON.stringify(data));
  };
  const saveProgData = (data) => {
    setProgramData(data);
    localStorage.setItem('indus_programData', JSON.stringify(data));
  };

  const saveCategory = (e) => {
    e.preventDefault();
    const id = catForm.id || catForm.label.toLowerCase().replace(/\s+/g, '-');
    const existing = categories.findIndex(c => c.id === id);
    const newCat = {
      ...catForm,
      id,
      programs: typeof catForm.programs === 'string' ? catForm.programs.split(',').map(s => s.trim()).filter(p => p) : catForm.programs
    };

    if (existing >= 0) {
      const updated = [...categories];
      updated[existing] = newCat;
      saveCats(updated);
    } else {
      saveCats([...categories, newCat]);
    }
    setCatForm({ id: '', label: '', badge: '', color: 'border-blue-500', bgColor: 'bg-blue-500', lightBg: 'bg-blue-50', programs: '' });
  };

  const handleProgramSelect = (prog) => {
    setSelectedProgramEdit(prog);
    const data = programData[prog] || { 'CURRICULUM & LEARNING': { sections: [{ title: 'Overview', items: ['Point 1'] }] } };
    setJsonInput(JSON.stringify(data, null, 2));
    setJsonError('');
  };

  const handleJsonSave = () => {
    try {
      const parsed = JSON.parse(jsonInput);
      setJsonError('');
      saveProgData({ ...programData, [selectedProgramEdit]: parsed });
      alert('Program details updated successfully!');
      setSelectedProgramEdit('');
    } catch(err) {
      setJsonError('Invalid JSON format: ' + err.message);
    }
  };

  const handleAddCourse = () => {
    if (!newCourseName.trim()) return;
    const updatedCats = categories.map(c => {
      if (c.id === selectedCategoryNav.id) {
        return { ...c, programs: [...c.programs, newCourseName.trim()] };
      }
      return c;
    });
    saveCats(updatedCats);
    setSelectedCategoryNav(updatedCats.find(c => c.id === selectedCategoryNav.id));
    setNewCourseName('');
    alert('New course added to track!');
  };

  const handleRemoveCourse = (courseName) => {
    if (!window.confirm(`Delete course "${courseName}"?`)) return;
    const updatedCats = categories.map(c => {
      if (c.id === selectedCategoryNav.id) {
        return { ...c, programs: c.programs.filter(p => p !== courseName) };
      }
      return c;
    });
    saveCats(updatedCats);
    setSelectedCategoryNav(updatedCats.find(c => c.id === selectedCategoryNav.id));
  };

  // --- RENDERING HELPERS ---

  if (selectedProgramEdit) {
    return (
      <div className="space-y-6 fade-in font-display">
        <div className="flex justify-between items-center bg-white/80 backdrop-blur-xl p-8 rounded-[2.5rem] border border-white/20 shadow-[0_20px_50px_-20px_rgba(0,0,0,0.1)]">
           <div className="flex items-center gap-6">
              <button 
                onClick={() => setSelectedProgramEdit('')}
                className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-400 hover:text-slate-900 hover:bg-slate-100 transition-all active:scale-90"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
              </button>
              <div>
                 <span className="text-[11px] font-black uppercase text-brand-brown tracking-[0.3em] block mb-1">Advanced Content Lab</span>
                 <h4 className="text-3xl font-black text-slate-900 tracking-tight">{selectedProgramEdit}</h4>
              </div>
           </div>
           <button onClick={handleJsonSave} className="bg-slate-900 text-white font-black px-10 py-4 rounded-2xl hover:shadow-2xl hover:-translate-y-1 transition-all active:scale-95 text-sm uppercase tracking-widest">Publish Changes</button>
        </div>

        <div className="relative group">
           <div className="absolute -inset-1 bg-gradient-to-r from-orange-500 to-amber-500 rounded-[3rem] blur opacity-10 group-hover:opacity-20 transition duration-1000"></div>
           <textarea 
              value={jsonInput} 
              onChange={e => setJsonInput(e.target.value)} 
              className="relative w-full bg-[#1c1c1e] text-[#e1e1e6] font-mono text-sm p-10 rounded-[3rem] min-h-[600px] shadow-2xl focus:outline-none focus:ring-4 ring-orange-500/20 border border-white/5 custom-scrollbar"
              spellCheck={false}
           ></textarea>
           {jsonError && <div className="absolute bottom-10 left-10 right-10 bg-red-500/90 text-white text-xs font-black p-5 rounded-2xl border border-red-400 backdrop-blur-md flex items-center gap-3">
             <span className="text-xl">⚠️</span> {jsonError}
           </div>}
        </div>
      </div>
    );
  }

  if (selectedCategoryNav) {
    return (
      <div className="space-y-10 fade-in font-display">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-8">
           <div className="flex items-center gap-6">
              <button 
                onClick={() => setSelectedCategoryNav(null)}
                className="group flex items-center px-8 py-4 bg-white rounded-2xl font-black text-slate-500 hover:text-slate-900 hover:shadow-xl transition-all border border-slate-100 active:scale-95"
              >
                <svg className="w-4 h-4 mr-3 group-hover:-translate-x-2 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
                EXIT TO TRACKS
              </button>
              <div>
                <span className="text-[10px] font-black text-brand-brown tracking-[0.4em] uppercase mb-1 block">Course Directory</span>
                <h2 className="text-5xl font-black text-slate-900 tracking-tighter">{selectedCategoryNav.label} <span className="text-slate-300">Spectrum</span></h2>
              </div>
           </div>
           <div className="relative group min-w-[320px]">
              <div className="absolute inset-y-0 left-6 flex items-center pointer-events-none">
                 <svg className="w-5 h-5 text-slate-300 group-focus-within:text-brand-brown transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/></svg>
              </div>
              <input 
                type="text" 
                placeholder="Filter programs..." 
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
                className="w-full bg-white border border-slate-100 pl-14 pr-8 py-4 rounded-2xl outline-none font-bold text-slate-700 shadow-sm focus:shadow-xl focus:border-brand-brown/20 transition-all"
              />
           </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
           {/* Add New Course Card */}
           <div className="bg-white/40 p-10 rounded-[3rem] border-4 border-dashed border-slate-200 flex flex-col justify-center items-center group hover:bg-white hover:border-brand-brown/40 transition-all relative overflow-hidden">
              <div className="absolute -top-10 -left-10 w-32 h-32 bg-slate-100 rounded-full blur-3xl opacity-50"></div>
              <div className="relative z-10 w-full">
                <input 
                  type="text" 
                  placeholder="New Program Name..." 
                  value={newCourseName}
                  onChange={e => setNewCourseName(e.target.value)}
                  className="w-full bg-slate-50 border-2 border-slate-100 rounded-[1.5rem] px-6 py-4 mb-5 font-black text-sm outline-none focus:bg-white focus:border-brand-brown/20 transition-all text-center"
                />
                <button 
                  onClick={handleAddCourse}
                  className="w-full bg-slate-900 text-white font-black py-5 rounded-[1.5rem] hover:shadow-[0_20px_40px_-10px_rgba(0,0,0,0.3)] hover:-translate-y-1 active:scale-95 transition-all text-xs tracking-[0.2em]"
                >
                  INITIALIZE COURSE
                </button>
              </div>
           </div>

           {selectedCategoryNav.programs
            .filter(p => p.toLowerCase().includes(searchQuery.toLowerCase()))
            .map((prog, idx) => (
              <div 
                key={idx} 
                className="bg-white p-10 rounded-[3rem] shadow-[0_15px_40px_-20px_rgba(0,0,0,0.05)] border border-slate-50 hover:shadow-2xl hover:border-brand-brown/10 transition-all group relative overflow-hidden flex flex-col justify-between min-h-[220px]"
              >
                <div className="relative z-10">
                   <div className="flex justify-between items-start mb-6">
                      <div className="w-14 h-14 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-300 group-hover:bg-brand-brown group-hover:text-white transition-all duration-500">
                         <span className="text-xl font-black">{prog.charAt(0)}</span>
                      </div>
                      <button 
                        onClick={(e) => { e.stopPropagation(); handleRemoveCourse(prog); }}
                        className="p-3 bg-red-50 text-red-200 hover:text-red-500 hover:bg-red-100 rounded-xl transition-all opacity-0 group-hover:opacity-100"
                      >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                      </button>
                   </div>
                   <h4 className="text-2xl font-black text-slate-800 leading-tight tracking-tight pr-4">{prog}</h4>
                </div>

                <button 
                   onClick={() => handleProgramSelect(prog)}
                   className="mt-8 flex items-center gap-3 text-[11px] font-black text-slate-400 group-hover:text-brand-brown tracking-[0.2em] uppercase transition-colors"
                >
                   Configure Content 
                   <svg className="w-4 h-4 group-hover:translate-x-2 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
                </button>

                <div className="absolute -bottom-10 -right-10 w-40 h-40 bg-slate-50 rounded-full opacity-0 group-hover:opacity-100 transition-opacity blur-3xl pointer-events-none"></div>
              </div>
           ))}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-16 fade-in font-display">
      {/* Category Management */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
        <div className="lg:col-span-4">
           <div className="bg-white/80 backdrop-blur-xl p-10 rounded-[3.5rem] shadow-2xl border border-white relative overflow-hidden">
             <div className="absolute top-0 right-0 w-32 h-32 bg-brand-brown/5 rounded-full blur-3xl"></div>
             <h3 className="text-3xl font-black mb-10 text-slate-900 tracking-tighter pr-4">{catForm.id ? 'Edit Meta' : 'Register New Track'}</h3>
             <form onSubmit={saveCategory} className="space-y-8">
                <div>
                  <label className="block text-[11px] font-black uppercase text-slate-400 tracking-widest mb-3 pr-2">Identity Label</label>
                  <input required type="text" placeholder="e.g. B.Tech" value={catForm.label} onChange={e => setCatForm({...catForm, label: e.target.value})} className="w-full bg-slate-50/50 p-5 rounded-2xl outline-none font-bold focus:bg-white border-2 border-transparent focus:border-brand-brown/10 transition-all text-lg" />
                </div>
                <div>
                  <label className="block text-[11px] font-black uppercase text-slate-400 tracking-widest mb-3 pr-2">Descriptor Badge</label>
                  <input required type="text" placeholder="e.g. DEGREE" value={catForm.badge} onChange={e => setCatForm({...catForm, badge: e.target.value})} className="w-full bg-slate-50/50 p-5 rounded-2xl outline-none font-bold uppercase focus:bg-white border-2 border-transparent focus:border-brand-brown/10 transition-all tracking-[0.2em]" />
                </div>
                <div>
                  <label className="block text-[11px] font-black uppercase text-slate-400 tracking-widest mb-3 pr-2">Program Stack (CSV)</label>
                  <textarea placeholder="List programs here..." value={typeof catForm.programs === 'string' ? catForm.programs : catForm.programs.join(', ')} onChange={e => setCatForm({...catForm, programs: e.target.value})} className="w-full bg-slate-50/50 p-5 rounded-2xl outline-none font-bold min-h-[160px] focus:bg-white border-2 border-transparent focus:border-brand-brown/10 transition-all text-sm leading-relaxed"></textarea>
                </div>
                <div className="flex flex-col gap-3 pt-4">
                  <button type="submit" className="w-full bg-slate-900 text-white font-black py-5 rounded-[1.5rem] hover:shadow-2xl hover:-translate-y-1 transition-all active:scale-95 text-xs tracking-[0.2em] uppercase">Save Academic Track</button>
                  {catForm.id && <button type="button" onClick={() => setCatForm({ id: '', label: '', badge: '', color: 'border-blue-500', bgColor: 'bg-blue-500', lightBg: 'bg-blue-50', programs: '' })} className="w-full py-4 text-slate-400 font-black hover:text-slate-900 transition-colors uppercase text-[10px] tracking-widest">Discard Changes</button>}
                </div>
             </form>
           </div>
        </div>

        <div className="lg:col-span-8">
           <div className="flex items-end justify-between mb-10 pl-2">
              <div>
                <span className="text-[10px] font-black text-brand-brown tracking-[0.4em] uppercase mb-1 block">Institutional Hierarchy</span>
                <h3 className="text-4xl font-black text-slate-900 tracking-tighter">Academic <span className="text-slate-300">Portfolio</span></h3>
              </div>
              <div className="text-[10px] font-black text-slate-400 tracking-[0.2em] uppercase bg-slate-100 px-4 py-2 rounded-full border border-slate-200">{categories.length} Active Tracks</div>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pb-12">
             {categories.map((cat) => (
               <div key={cat.id} className="bg-white p-10 rounded-[3.5rem] shadow-[0_20px_50px_-20px_rgba(0,0,0,0.05)] border border-slate-50 relative group hover:shadow-2xl transition-all overflow-hidden flex flex-col justify-between min-h-[300px]">
                  <div className="absolute top-0 right-0 w-24 h-24 bg-slate-50 rounded-bl-[3rem] -z-0 group-hover:bg-[#6f5c4e] transition-colors duration-500"></div>

                  <div className="relative z-10">
                     <span className="inline-block px-3 py-1 bg-slate-50 rounded-full text-[10px] font-black text-slate-400 tracking-[0.1em] mb-6 uppercase border border-slate-100">{cat.badge}</span>
                     <h4 className="text-4xl font-black text-slate-900 mb-2 group-hover:text-slate-900 transition-colors">{cat.label}</h4>
                     <p className="text-[11px] font-black text-slate-300 tracking-[0.2em] uppercase italic">Academic Specialization</p>
                  </div>

                  <div className="relative z-10 mt-12 flex items-center gap-2">
                     <button onClick={() => setSelectedCategoryNav(cat)} className="flex-1 bg-slate-900 text-white text-[10px] font-black py-4 rounded-2xl hover:scale-105 active:scale-95 transition-all uppercase tracking-widest">Manage Content</button>
                     <button onClick={() => setCatForm(cat)} className="w-14 h-14 bg-slate-50 flex items-center justify-center rounded-2xl text-slate-400 hover:bg-brand-brown hover:text-white transition-all"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
                     <button onClick={() => confirmDelete('category', cat.id, cat.label)} className="w-14 h-14 bg-red-50 text-red-200 flex items-center justify-center rounded-2xl hover:bg-red-500 hover:text-white transition-all"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                  </div>
               </div>
             ))}
           </div>
        </div>
      </div>
    </div>
  );
}
